#include <bits/stdc++.h>
using namespace std;
string x,y;
int a[1000000],b[1000000],c[1000000];
int main() {
	cin>>x>>y;
	if(x.size()<y.size()){
		cout<<'-';
		swap(x,y);
	}
	if(x.size()==y.size()){
		if(x<y){
			cout<<'-';
			swap(x,y);
		}
	}
	a[0]=x.size(),b[0]=y.size();
	c[0]=max(a[0],b[0]);
	for(int i=0;i<a[0];i++){
		a[i+1]=x[a[0]-i-1]-'0';
	}
	for(int i=0;i<b[0];i++){
		b[i+1]=y[b[0]-i-1]-'0';
	}
	for(int i=1;i<=c[0];i++){
		if(a[i]<b[i]){
			a[i]+=10;
			a[i+1]--;
		}
		c[i]=a[i]-b[i];
	}
	while(c[c[0]]==0&&c[0]>1){
		c[0]--;
	}
	for(int i=c[0];i>=1;i--){
		cout<<c[i];
	}
	return 0;
}
